1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("should return empty array when given empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent live cells (each has only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a live cell alive when it has 2 live neighbors (survival)", () => {
15	    // Vertical line of 3 cells - center cell (0,1) has 2 live neighbors and survives
16	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
17	    expect(result).toContainEqual([0, 1]);
18	  });
19	  it("should kill a live cell with more than 3 neighbors (overpopulation)", () => {
20	    // Center (1,1) has 4 live neighbors at the corners, so it dies
21	    const result = nextGeneration([[1, 1], [0, 0], [2, 0], [0, 2], [2, 2]]);
22	    expect(result).not.toContainEqual([1, 1]);
23	  });
24	  it("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)", () => {
25	    // Dead cell at (1,1) has 3 live neighbors: (0,0), (1,0), (0,1) → becomes alive
26	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
27	    expect(result).toContainEqual([1, 1]);
28	  });
29	  it("should oscillate a blinker pattern from vertical to horizontal", () => {
30	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
31	    const result = nextGeneration(vertical);
32	    expect(result.sort()).toEqual([[-1, 1], [0, 1], [1, 1]].sort());
33	  });
34	  it("should keep a block pattern unchanged (still life)", () => {
35	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
36	    const result = nextGeneration(block);
37	    expect(result.sort()).toEqual(block.sort());
38	  });
39	  it("should handle negative coordinates", () => {
40	    // Blinker at negative coordinates: vertical line at x=-5
41	    const vertical: [number, number][] = [[-5, -5], [-5, -4], [-5, -3]];
42	    const result = nextGeneration(vertical);
43	    expect(result.sort()).toEqual([[-6, -4], [-5, -4], [-4, -4]].sort());
44	  });
45	});
